class Solution:
    def numberOfWays(self, n: int, x: int) -> int:
        MOD = 10**9 + 7
        res = 0
        for i in range(1, n + 1):
            if i ** x <= n:
                res += self.countWays(n - i ** x, x, i, MOD)
            else:
                break
        return res
    def countWays(self, n: int, x: int, i: int, MOD: int) -> int:
        if n == 0:
            return 1
        res = 0
        for j in range(i + 1, n + 1):
            if j ** x <= n:
                res += self.countWays(n - j ** x, x, j, MOD)
        return res % MOD
